SELECT TOP 1 COUNT(*) AS TOTAL_SCHEDULES,
	SUM(S.[TOTAL_SEATS]) AS TOTAL_CAPACITY,
	SUM(S.[AVAILABLE_SEATS]) AS AVAILABLE_CAPACITY 
